import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { Line } from 'react-chartjs-2'
import { pondService, sensorService, environmentLogService } from '../../services/api'
import { showToast } from '../../utils/toast'
import { getSensorProfile, getSensorTypeKey, SENSOR_ORDER } from '../../utils/sensorMetrics'
import '../../styles/owner/owner-sensor-data.css'

import {
	Chart as ChartJS,
	CategoryScale,
	LinearScale,
	PointElement,
	LineElement,
	Title,
	Tooltip,
	Legend,
	Filler,
} from 'chart.js'

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend, Filler)

const METRIC_DEFINITIONS = [
	{ code: 'ph', label: 'Độ pH', unit: 'pH', icon: '🔬', minKey: 'minPh', maxKey: 'maxPh', defaultMin: 7.4, defaultMax: 8.5, precision: 1 },
	{ code: 'temperature', label: 'Nhiệt độ nước', unit: '°C', icon: '🌡️', minKey: 'minTemp', maxKey: 'maxTemp', defaultMin: 26, defaultMax: 32, precision: 1 },
	{ code: 'oxygen', label: 'Oxy hòa tan (DO)', unit: 'mg/L', icon: '💨', minKey: 'minOxygen', maxKey: 'maxOxygen', defaultMin: 4.5, defaultMax: 8, precision: 1 },
	{ code: 'salinity', label: 'Độ mặn', unit: 'ppt', icon: '🧂', minKey: 'minSalinity', maxKey: 'maxSalinity', defaultMin: 12, defaultMax: 25, precision: 1 },
	{ code: 'turbidity', label: 'Độ đục', unit: 'NTU', icon: '🌫️', minKey: 'minTurbidity', maxKey: 'maxTurbidity', defaultMin: 0, defaultMax: 10, precision: 1 },
]

const SENSOR_STATUS_STALE_MINUTES = 15

const normalizeThresholdForm = (data = {}) => ({
	minPh: data.min_ph ?? data.minPh ?? null,
	maxPh: data.max_ph ?? data.maxPh ?? null,
	minTemp: data.min_temp ?? data.minTemp ?? null,
	maxTemp: data.max_temp ?? data.maxTemp ?? null,
	minOxygen: data.min_oxygen ?? data.minOxygen ?? null,
	maxOxygen: data.max_oxygen ?? data.maxOxygen ?? null,
	minSalinity: data.min_salinity ?? data.minSalinity ?? null,
	maxSalinity: data.max_salinity ?? data.maxSalinity ?? null,
	minTurbidity: data.min_turbidity ?? data.minTurbidity ?? null,
	maxTurbidity: data.max_turbidity ?? data.maxTurbidity ?? null,
	alertLevel: data.alert_level ?? data.alertLevel ?? 'WARNING',
	notes: data.notes ?? null,
})

const toNullableNumber = (value) => {
	if (value === '' || value === null || value === undefined) return null
	const parsed = Number(value)
	return Number.isFinite(parsed) ? parsed : null
}

const formatNumber = (value, precision = 1) => {
	if (value === null || value === undefined || value === '') return '--'
	const parsed = Number(value)
	if (Number.isNaN(parsed)) return String(value)
	return parsed.toFixed(precision)
}

const formatDateTime = (raw) => {
	if (!raw) return '--'
	const date = new Date(raw)
	if (Number.isNaN(date.getTime())) return '--'
	return date.toLocaleString('vi-VN', {
		day: '2-digit',
		month: '2-digit',
		year: 'numeric',
		hour: '2-digit',
		minute: '2-digit',
	})
}

const getSensorStatusState = (sensor) => {
	const baseStatus = String(sensor?.status || '').trim().toUpperCase()
	if (baseStatus === 'INACTIVE') return 'INACTIVE'

	const lastUpdated = sensor?.last_updated ? new Date(sensor.last_updated).getTime() : 0
	if (!lastUpdated) return 'DISCONNECTED'

	const staleWindow = SENSOR_STATUS_STALE_MINUTES * 60 * 1000
	if (Date.now() - lastUpdated > staleWindow) return 'DISCONNECTED'

	return 'ACTIVE'
}

const getPondLabel = (pond) => `${pond?.pond_code || 'AO'} - ${pond?.pond_name || 'Không tên'}`

const getStatusLabel = (status) => {
	switch (status) {
		case 'danger':
			return 'Nguy hiểm'
		case 'warning':
			return 'Cảnh báo'
		case 'missing':
			return 'Không có dữ liệu'
		default:
			return 'Bình thường'
	}
}

const getMetricThresholdValue = (thresholds, metric, field) => {
	const key = field === 'min' ? metric.minKey : metric.maxKey
	return toNullableNumber(thresholds?.[key])
}

const PondRealtimeSection = ({ pond, realtimeMap }) => {
	const cards = useMemo(() => {
		return METRIC_DEFINITIONS.map((metric) => {
			const entry = realtimeMap[metric.code] || null
			const current = toNullableNumber(entry?.latest?.value)
			const thresholdMin = getMetricThresholdValue(entry?.thresholdData, metric, 'min')
			const thresholdMax = getMetricThresholdValue(entry?.thresholdData, metric, 'max')
			const fallbackMin = thresholdMin ?? metric.defaultMin
			const fallbackMax = thresholdMax ?? metric.defaultMax
			const dangerMode = String(entry?.thresholdData?.alertLevel || 'WARNING').toUpperCase()
			let status = 'normal'

			if (current === null) {
				status = 'missing'
			} else if ((thresholdMin !== null && current < thresholdMin) || (thresholdMax !== null && current > thresholdMax)) {
				status = dangerMode === 'DANGER' ? 'danger' : 'warning'
			}

			const denom = (fallbackMax - fallbackMin) || 1
			const fill = current === null ? 0 : Math.max(0, Math.min(100, ((current - fallbackMin) / denom) * 100))

			return {
				...metric,
				current,
				status,
				updatedAt: entry?.latest?.recorded_at || null,
				fill,
				thresholdMin,
				thresholdMax,
				serialNumber: entry?.sensor?.serial_number || '-',
			}
		})
	}, [realtimeMap])

	const chartData = useMemo(() => {
		const timestamps = new Set()
		const chartSeries = []

		METRIC_DEFINITIONS.forEach((metric) => {
			const entry = realtimeMap[metric.code]
			if (!entry?.readings?.length) return

			entry.readings.forEach((reading) => {
				if (reading?.recorded_at) {
					timestamps.add(new Date(reading.recorded_at).toISOString())
				}
			})

			chartSeries.push({ metric, readings: entry.readings })
		})

		const labelsIso = Array.from(timestamps).sort()
		const labels = labelsIso.map((iso) => new Intl.DateTimeFormat('vi-VN', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Ho_Chi_Minh' }).format(new Date(iso)))
		const colors = ['#2563eb', '#10b981', '#f97316', '#8b5cf6', '#ef4444']

		return {
			labels,
			datasets: chartSeries.map((series, index) => {
				const valueMap = new Map()
				series.readings.forEach((reading) => {
					if (reading?.recorded_at) {
						valueMap.set(new Date(reading.recorded_at).toISOString(), Number(reading.value))
					}
				})

				const color = colors[index % colors.length]
				return {
					label: series.metric.label,
					data: labelsIso.map((iso) => (valueMap.has(iso) ? valueMap.get(iso) : null)),
					borderColor: color,
					backgroundColor: `${color}26`,
					pointRadius: 2,
					tension: 0.35,
					fill: true,
				}
			}),
		}
	}, [realtimeMap])

	const chartOptions = useMemo(() => ({
		responsive: true,
		maintainAspectRatio: false,
		plugins: {
			legend: { display: true, position: 'top', labels: { usePointStyle: true, boxWidth: 8 } },
		},
		scales: {
			x: { grid: { color: 'rgba(148, 163, 184, 0.18)' } },
			y: { grid: { color: 'rgba(148, 163, 184, 0.18)' } },
		},
	}), [])

	const activeCount = cards.filter((card) => card.status !== 'missing').length

	return (
		<section className="owner-sensor-data_pond-card">
			<div className="owner-sensor-data_pond-head">
				<div>
					<h3>{getPondLabel(pond)}</h3>
					<p>{activeCount} cảm biến realtime đang được theo dõi</p>
				</div>
				<span className="owner-sensor-data_pond-badge">{pond?.status || 'Ao nuôi'}</span>
			</div>

			<div className="owner-sensor-data_cards">
				{cards.map((card) => (
					<article key={card.code} className={`owner-sensor-data_card owner-sensor-data_card--${card.status}`}>
						<div className="owner-sensor-data_card-head">
							<div>
								<span>{card.icon}</span>
								<strong>{card.label}</strong>
							</div>
							<small>{getStatusLabel(card.status)}</small>
						</div>
						<div className="owner-sensor-data_card-value">
							{card.current !== null ? formatNumber(card.current, card.precision) : '--'} <span>{card.unit}</span>
						</div>
						<div className="owner-sensor-data_card-bar"><span style={{ width: `${card.fill}%` }} /></div>
						<div className="owner-sensor-data_card-meta">
							Mã cảm biến: {card.serialNumber}
							<br />
							Cập nhật gần nhất: {formatDateTime(card.updatedAt)}
						</div>
					</article>
				))}
			</div>

			<div className="owner-sensor-data_chart-card">
				<div className="owner-sensor-data_section-head owner-sensor-data_section-head--compact">
					<h4>Biểu đồ realtime</h4>
					<span>Theo dõi biến động của toàn bộ cảm biến trong ao</span>
				</div>
				<div className="owner-sensor-data_chart-wrap">
					{chartData.datasets.length > 0 ? <Line data={chartData} options={chartOptions} /> : <div className="owner-sensor-data_empty-chart">Chưa có dữ liệu realtime cho ao này.</div>}
				</div>
			</div>
		</section>
	)
}

const OwnerSensorData = () => {
	const [ponds, setPonds] = useState([])
	const [allSensors, setAllSensors] = useState([])
	const [pondRealtime, setPondRealtime] = useState({})
	const [loading, setLoading] = useState(true)
	const [refreshing, setRefreshing] = useState(false)

	const loadRealtimeData = useCallback(async (options = {}) => {
		const { silent = false } = options
		if (!silent) setLoading(true)

		try {
			const [pondRes, sensorRes] = await Promise.all([
				pondService.getAllPonds(),
				sensorService.getAllSensors(),
			])

			const nextPonds = pondRes?.data?.data || []
			const nextSensors = sensorRes?.data?.data || []
			setPonds(nextPonds)
			setAllSensors(nextSensors)

			if (!silent) setRefreshing(true)

			const realtimeMap = {}
			await Promise.all(
				nextPonds.map(async (pond) => {
					const pondSensors = nextSensors.filter((sensor) => String(sensor.pond_id) === String(pond.pond_id))
					const metricMap = {}

					await Promise.all(
						pondSensors.map(async (sensor) => {
							const metricKey = getSensorTypeKey(sensor.sensor_type)
							if (!metricKey) return

							try {
								const [readingsRes, thresholdsRes] = await Promise.all([
									sensorService.getSensorReadings(sensor.sensor_id, 60),
									environmentLogService.getThresholdsBySensor(sensor.sensor_id),
								])

								const readings = [...(readingsRes?.data?.data || [])].reverse()
								const latest = readings[readings.length - 1] || null
								const thresholdData = normalizeThresholdForm(thresholdsRes?.data?.data || {})

								if (!metricMap[metricKey] || new Date(latest?.recorded_at || 0).getTime() > new Date(metricMap[metricKey].latest?.recorded_at || 0).getTime()) {
									metricMap[metricKey] = { sensor, readings, latest, thresholdData }
								}
							} catch (readingError) {
								console.error('Error loading owner sensor realtime:', readingError)
							}
						})
					)

					realtimeMap[String(pond.pond_id)] = metricMap
				})
			)

			setPondRealtime(realtimeMap)
		} catch (error) {
			showToast({ title: error?.response?.data?.message || 'Không tải được dữ liệu cảm biến', type: 'error' })
		} finally {
			if (!silent) {
				setLoading(false)
				setRefreshing(false)
			}
		}
	}, [])

	useEffect(() => {
		loadRealtimeData()
	}, [loadRealtimeData])

	useEffect(() => {
		const interval = setInterval(() => {
			loadRealtimeData({ silent: true })
		}, 30000)

		return () => clearInterval(interval)
	}, [loadRealtimeData])

	const summary = useMemo(() => {
		const total = allSensors.length
		const active = allSensors.filter((sensor) => getSensorStatusState(sensor) === 'ACTIVE').length
		const paused = allSensors.filter((sensor) => getSensorStatusState(sensor) === 'INACTIVE').length
		const disconnected = allSensors.filter((sensor) => getSensorStatusState(sensor) === 'DISCONNECTED').length

		return {
			ponds: ponds.length,
			total,
			active,
			paused,
			disconnected,
		}
	}, [allSensors, ponds])

	const sortedPonds = useMemo(() => {
		return [...ponds].sort((a, b) => Number(a?.pond_id || 0) - Number(b?.pond_id || 0))
	}, [ponds])

	const sensorRows = useMemo(() => {
		return [...allSensors].sort((a, b) => Number(a?.sensor_id || 0) - Number(b?.sensor_id || 0))
	}, [allSensors])

	if (loading) {
		return (
			<div className="dashboard owner-page-shell owner-sensor-data_page">
				<div className="flex-center owner-sensor-data_loading">
					<div className="spinner" />
				</div>
			</div>
		)
	}

	return (
		<div className="dashboard owner-page-shell owner-sensor-data_page">
			<div className="table-container table-panel owner-sensor-data_panel-shell">
				<div className="table-header table-header">
					<div>
						<h2>Dữ liệu cảm biến</h2>
						<p className="table-subtitle">Xem realtime toàn bộ cảm biến theo từng ao trong trại nuôi.</p>
					</div>
					<div className="owner-sensor-data_header-actions">
						<button type="button" className="btn btn-secondary" onClick={() => loadRealtimeData()} disabled={refreshing}>
							{refreshing ? 'Đang cập nhật...' : 'Làm mới dữ liệu'}
						</button>
					</div>
				</div>

				<section className="stats-grid owner-sensor-data_stats-grid">
					<article className="stats-card stats-card--primary">
						<span className="stats-card-label">Ao đang theo dõi</span>
						<strong className="stats-card-value">{summary.ponds}</strong>
					</article>
					<article className="stats-card stats-card--primary">
						<span className="stats-card-label">Tổng cảm biến</span>
						<strong className="stats-card-value">{summary.total}</strong>
					</article>
					<article className="stats-card stats-card--success">
						<span className="stats-card-label">Cảm biến hoạt động</span>
						<strong className="stats-card-value">{summary.active}</strong>
					</article>
					<article className="stats-card stats-card--warning">
						<span className="stats-card-label">Cảm biến tạm ngưng</span>
						<strong className="stats-card-value">{summary.paused}</strong>
					</article>
					<article className="stats-card stats-card--info">
						<span className="stats-card-label">Cảm biến mất kết nối</span>
						<strong className="stats-card-value">{summary.disconnected}</strong>
					</article>
				</section>

				<section className="owner-sensor-data_ponds">
					<div className="owner-sensor-data_section-head">
						<div>
							<h2>Realtime tất cả ao nuôi</h2>
							<p>Mỗi ao hiển thị đồng thời dữ liệu realtime, biểu đồ và trạng thái theo ngưỡng hiện hành.</p>
						</div>
						<span className="owner-sensor-data_refresh-label">Tự làm mới mỗi 30 giây</span>
					</div>

					<div className="owner-sensor-data_pond-list">
						{sortedPonds.length === 0 ? (
							<div className="owner-sensor-data_empty-state">Chưa có ao nào trong trại nuôi.</div>
						) : (
							sortedPonds.map((pond) => (
								<PondRealtimeSection key={pond.pond_id} pond={pond} realtimeMap={pondRealtime[String(pond.pond_id)] || {}} />
							))
						)}
					</div>
				</section>

				<section className="owner-sensor-data_table-section">
					<div className="owner-sensor-data_section-head owner-sensor-data_section-head--compact">
						<div>
							<h3>Danh sách cảm biến</h3>
							<p>Chế độ chỉ xem, không hỗ trợ thêm, xoá hay thiết lập ngưỡng.</p>
						</div>
					</div>

					<div className="table-wrapper">
						<table className="table-base owner-sensor-data_table">
							<thead>
								<tr>
									<th>Mã cảm biến</th>
									<th>Loại cảm biến</th>
									<th>Ao nuôi</th>
									<th>Trạng thái</th>
									<th>Cập nhật gần nhất</th>
								</tr>
							</thead>
							<tbody>
								{sensorRows.length === 0 ? (
									<tr>
										<td colSpan="5" className="table-empty-row">Không có dữ liệu cảm biến.</td>
									</tr>
								) : (
									sensorRows.map((sensor) => {
										const statusState = getSensorStatusState(sensor)
										return (
											<tr key={sensor.sensor_id}>
												<td>{sensor.serial_number || '-'}</td>
												<td>{getSensorProfile(getSensorTypeKey(sensor.sensor_type))?.label || sensor.sensor_type || '-'}</td>
												<td>{getPondLabel(sortedPonds.find((pond) => String(pond.pond_id) === String(sensor.pond_id)))}</td>
												<td>
													<span className={`owner-sensor-data_status owner-sensor-data_status--${statusState.toLowerCase()}`}>
														{statusState === 'ACTIVE' ? 'Hoạt động' : statusState === 'INACTIVE' ? 'Tạm ngưng' : 'Mất kết nối'}
													</span>
												</td>
												<td>{formatDateTime(sensor.last_updated)}</td>
											</tr>
										)
									})
								)}
							</tbody>
						</table>
					</div>
				</section>
			</div>
		</div>
	)
}

export default OwnerSensorData
